/**
 * Find the next high tide after a given time.
 * @param {Array} tides - array of tide objects with time, type, height
 * @param {string} after - ISO date string to search after
 * @returns {Object} the next high tide object
 * @throws {Error} if no upcoming high tide exists
 * @planks("I ask for the next high tide after {string}")
 */
function nextHighTide(tides, after) {
  const next = tides.find((t) => new Date(t.time) > new Date(after) && t.type === "high");
  if (!next) throw new Error("no upcoming high tide in data");
  return next;
}

module.exports = { nextHighTide };
